import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Pie, Line } from 'react-chartjs-2';
import 'chart.js/auto';
import './Dashboard.css';

export default function Dashboard() {
    const [portfolio, setPortfolio] = useState([]);
    const [priceHistory, setPriceHistory] = useState([]);
    const [loading, setLoading] = useState(true);

    // ✅ Récupération des actifs du portefeuille depuis le backend
    useEffect(() => {
        axios.get('http://localhost:9000/portfolio/johnDoe') // Remplace "johnDoe" par l'utilisateur connecté
            .then(response => {
                setPortfolio(response.data);
                setLoading(false);
            })
            .catch(error => console.error("Erreur récupération portefeuille :", error));
    }, []);

    // ✅ Récupération de l'historique des prix
    useEffect(() => {
        axios.get('http://localhost:9000/price-history/AAPL') // Remplace "AAPL" par un actif dynamique
            .then(response => {
                setPriceHistory(response.data);
            })
            .catch(error => console.error("Erreur récupération prix :", error));
    }, []);

    // 📊 **Données pour le graphique en secteurs (Pie Chart)**
    const pieData = {
        labels: portfolio.map(asset => asset.symbol),
        datasets: [{
            data: portfolio.map(asset => asset.quantity),
            backgroundColor: ['#FF6384', '#36A2EB', '#FFCE56', '#4CAF50', '#FF9800'],
        }]
    };

    // 📈 **Données pour le graphique en courbe (Line Chart)**
    const lineData = {
        labels: priceHistory.map(price => new Date(price.timestamp).toLocaleTimeString()),
        datasets: [{
            label: "Prix de l'actif",
            data: priceHistory.map(price => price.price),
            fill: false,
            borderColor: '#FF6384'
        }]
    };

    return (
        <div className="dashboard-container">
            <h2>📊 Tableau de bord</h2>

            {loading ? <p>Chargement du portefeuille...</p> : (
                <>
                    <div className="charts-container">
                        <div className="chart">
                            <h3>Répartition des actifs</h3>
                            <Pie data={pieData} />
                        </div>
                        <div className="chart">
                            <h3>Performance du portefeuille</h3>
                            <Line data={lineData} />
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}
